int hIndex(int* citations, int n) {
    int* count = calloc(n + 1, sizeof(int));
    for (int i = 0; i < n; i++) count[citations[i] > n ? n : citations[i]]++;
    int papers = 0;
    for (int h = n; h >= 0; h--) {
        papers += count[h];
        if (papers >= h) { free(count); return h; }
    }
    free(count);
    return 0;
}
